<template><div class="page"><h2 class="page-title">实时摄像头检测</h2><div class="panel camera"><div class="toolbar"><el-button type="success" @click="start">开启摄像头</el-button><el-button type="danger" @click="stop">停止检测</el-button><span>实时缺陷：{{defects.length}}</span></div><div class="stage"><video ref="videoRef" autoplay muted playsinline></video><canvas ref="canvasRef"></canvas></div><el-table :data="defects"><el-table-column prop="category_name" label="类别"/><el-table-column prop="confidence" label="置信度"/><el-table-column prop="bbox" label="坐标"/></el-table></div></div></template><script setup>
import { onBeforeUnmount, ref } from 'vue'; import { detectCameraFrame } from '../../api/detection.js'
const videoRef=ref(), canvasRef=ref(), stream=ref(null), timer=ref(null), defects=ref([])
async function start(){ stream.value=await navigator.mediaDevices.getUserMedia({video:true}); videoRef.value.srcObject=stream.value; timer.value=setInterval(capture,800) }
function stop(){ if(timer.value) clearInterval(timer.value); stream.value?.getTracks().forEach(t=>t.stop()); timer.value=null; stream.value=null }
async function capture(){ const v=videoRef.value,c=canvasRef.value; if(!v?.videoWidth)return; c.width=v.videoWidth;c.height=v.videoHeight; const ctx=c.getContext('2d'); ctx.drawImage(v,0,0,c.width,c.height); const blob=await new Promise(r=>c.toBlob(r,'image/jpeg',.85)); const fd=new FormData(); fd.append('file',blob,'frame.jpg'); const res=await detectCameraFrame(fd); defects.value=res.defects||[]; ctx.drawImage(v,0,0,c.width,c.height); defects.value.forEach(d=>{ const [x1,y1,x2,y2]=d.bbox; ctx.strokeStyle=d.color||'#38bdf8'; ctx.lineWidth=3; ctx.strokeRect(x1,y1,x2-x1,y2-y1); ctx.fillStyle=d.color||'#38bdf8'; ctx.fillText(`${d.category_name} ${d.confidence}`,x1,y1>16?y1-4:y1+16) }) }
onBeforeUnmount(stop)
</script><style scoped>.camera{padding:20px}.toolbar{display:flex;gap:12px;align-items:center;margin-bottom:16px}.stage{position:relative;max-width:960px;background:#000;border-radius:16px;overflow:hidden}.stage video,.stage canvas{width:100%;display:block}.stage canvas{position:absolute;inset:0}</style>